/bin/bash -lc "python - <<'PY'
import requests
u='https://huggingface.co/api/datasets/songlab/TraitGym/tree/main'
r=requests.get(u,params={'recursive':'true','expand':'false','limit':1000}); print(r.status_code,len(r.text)); print(r.text[:500]);
if r.ok:
 x=r.json(); print(len(x));
 for z in x:
  p=z.get('path','')
  if 'preds/' in p and ('CADD' in p or 'GPN' in p or 'Borzoi' in p): print(p,z.get('size'))
PY"

