python - <<'PY'
import requests, pathlib
base='https://huggingface.co/datasets/songlab/TraitGym/resolve/main'
for ds in ['complex_traits_matched_9','mendelian_traits_matched_9']:
 for f in ['CADD%2BGPN-MSA%2BBorzoi.LogisticRegression.chrom.parquet','CADD%2BGPN-MSA_LLR%2BBorzoi_L2_L2.LogisticRegression.chrom.parquet','GPN-MSA.LogisticRegression.chrom.parquet','Borzoi.LogisticRegression.chrom.parquet']:
  u=f'{base}/{ds}/preds/all/{f}?download=true'; out=pathlib.Path('public_predictions')/(ds+'__'+f.replace('%2B','+'))
  r=requests.get(u); print(ds,f,r.status_code,len(r.content),r.url)
  if r.ok: out.write_bytes(r.content)
PY
